            field_value = result_metadata.get(field_name)

            for operator, expected_value in filter_condition.items():
                if operator == "==":
                    if field_value != expected_value:
                        matches = False
                        break
                elif operator == "!=":
                    if field_value == expected_value:
                        matches = False
                        break
