from typing import List, Dict, Any
from leann.api import PassageManager, LeannSearcher
from pathlib import Path
import json
from collections import Counter, defaultdict

def get_index_statistics(
    index_path: str
) -> Dict[str, Any]:
    """Get comprehensive statistics about a LEANN index.

Args:
    index_path: Path to the LEANN index file

Returns:
    Dictionary containing:
    {
        "total_passages": total number of passages,
        "metadata_fields": list of unique metadata field names,
        "field_value_counts": dictionary of field value counts
    }

Raises:
    FileNotFoundError: If index metadata file is not found"""
    searcher = LeannSearcher(index_path)
    passage_sources = searcher.passage_manager.get_passage_sources()
    total_passages = 0
    field_counts = defaultdict(Counter)
    all_fields = set()

    for source in passage_sources:
        passage_file = source['path']
        with open(passage_file, 'r', encoding='utf-8') as f:
            for line_num, line in enumerate(f, 1):
                try:
                    data = json.loads(line.strip())
                    # Exclude the 'id' field
                    fields = {k: v for k, v in data.items() if k != 'id'}
                    for field_name, field_value in fields.items():
                        field_counts[field_name][field_value] += 1
                    all_fields.update(fields.keys())
                    total_passages += 1
                except Exception:
                    # Skip invalid lines
                    continue

    field_value_counts = {k: dict(v) for k, v in field_counts.items()}
    return {
        "total_passages": total_passages,
        "metadata_fields": sorted(all_fields),
        "field_value_counts": field_value_counts
    }

def analyze_index_coverage(index_path: str, required_fields: List[str]) -> Dict[str, Any]:
    """Analyze how well an index covers required metadata fields.

Args:
    index_path: Path to the LEANN index file
    required_fields: List of metadata field names that should be present

Returns:
    Dictionary containing:
    {
        "coverage_percentage": percentage of passages that have all required fields,
        "field_coverage": dictionary mapping field name to coverage percentage,
        "missing_fields": list of required fields not found in any passage
    }

Raises:
    FileNotFoundError: If index metadata file is not found"""
    searcher = LeannSearcher(index_path)
    passage_sources = searcher.passage_manager.get_passage_sources()
    total_passages = 0
    covered = 0
    field_counts = {field: 0 for field in required_fields}
    required_field_found = {field: False for field in required_fields}

    for source in passage_sources:
        passage_file = source['path']
        with open(passage_file, 'r', encoding='utf-8') as f:
            for line_num, line in enumerate(f, 1):
                try:
                    data = json.loads(line.strip())
                    passage_fields = set(data.keys()) - {'id'}
                    total_passages += 1
                    # Check if all required fields are present
                    if all(field in passage_fields for field in required_fields):
                        covered += 1
                    # Count individual fields
                    for field in required_fields:
                        if field in passage_fields:
                            field_counts[field] += 1
                    # Check if required fields are found at least once
                    for field in required_fields:
                        if not required_field_found[field]:
                            if field in passage_fields:
                                required_field_found[field] = True
                except Exception:
                    continue

    coverage_percentage = (covered / total_passages * 100) if total_passages > 0 else 0.0
    field_coverage = {field: (count / total_passages * 100) if total_passages > 0 else 0.0 
                      for field, count in field_counts.items()}

    missing_fields = [field for field, found in required_field_found.items() if not found]

    return {
        "coverage_percentage": round(coverage_percentage, 2),
        "field_coverage": {k: round(v, 2) for k, v in field_coverage.items()},
        "missing_fields": missing_fields
    }
